return ['domain'=>'magicauth','plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'de_DE','project-id-version'=>'MagicAuth 1.0.3','pot-creation-date'=>'2026-05-22T19:10:14+00:00','po-revision-date'=>'2026-05-22','x-generator'=>'MagicAuth i18n generator','messages'=>['Passwordless WordPress sign-in via email magic link or 6-character code.'=>'Passwortlose WordPress-Anmeldung per E-Mail-Magic-Link oder 6-stelligem Code.','MagicAuth by Ettic.'=>'MagicAuth von Ettic.','Focused, open-source WordPress plugins.'=>'Fokussierte Open-Source-WordPress-Plugins.','MagicAuth resources'=>'MagicAuth-Ressourcen','Docs'=>'Dokumentation','Support'=>'Support','Report a vulnerability'=>'Sicherheitslücke melden','Like MagicAuth? Leave a review and help us keep building open source.'=>'Gefällt Ihnen MagicAuth? Hinterlassen Sie eine Bewertung und helfen Sie uns, weiter Open Source zu entwickeln.','Leave a review'=>'Bewertung abgeben','Settings'=>'Einstellungen','Discard'=>'Verwerfen','Save changes'=>'Änderungen speichern','Passwordless sign-in via magic link or 6-character code. Configure how it looks, how it behaves, and how it recovers from edge cases. All on one page.'=>'Passwortlose Anmeldung per Magic-Link oder 6-stelligem Code. Legen Sie fest, wie sie aussieht, wie sie sich verhält und wie sie sich von Sonderfällen erholt. Alles auf einer Seite.','General'=>'Allgemein','How long links live and where users land afterwards.'=>'Wie lange Links gültig sind und wo Nutzer danach landen.','Branding'=>'Branding','How the sign-in card looks. Settings render on the branded login screen and in transactional emails.'=>'Wie die Anmeldekarte aussieht. Diese Einstellungen erscheinen auf dem gebrandeten Anmeldebildschirm und in Transaktions-E-Mails.','Agency credit'=>'Agentur-Credit','Optional "Built by [Brand]" line below the sign-in card. Renders only when name, URL, and favicon are all filled.'=>'Optionale Zeile "Erstellt von [Marke]" unter der Anmeldekarte. Wird nur angezeigt, wenn Name, URL und Favicon ausgefüllt sind.','Security &amp; throttling'=>'Sicherheit &amp; Drosselung','Recovery layers and rate-limit caps. The "Sign in with password" link is the unconditional safety net. Disable it only after site-wide password auth is already off.'=>'Wiederherstellungsebenen und Ratenbegrenzungen. Der Link "Mit Passwort anmelden" ist das bedingungslose Sicherheitsnetz. Deaktivieren Sie ihn erst, nachdem die Passwort-Anmeldung site-weit bereits deaktiviert ist.','Diagnostics &amp; recovery'=>'Diagnose &amp; Wiederherstellung','One-shot tools for debugging and unsticking the plugin. Destructive actions ask for confirmation.'=>'Einmal-Werkzeuge zum Debuggen und Entsperren des Plugins. Destruktive Aktionen erfordern eine Bestätigung.','Send test email'=>'Test-E-Mail senden','One-shot diagnostic. No tokens are issued. Forces the default brand color to verify rendering.'=>'Einmalige Diagnose. Es werden keine Token ausgegeben. Erzwingt die Standard-Markenfarbe, um die Darstellung zu prüfen.','Send to my account'=>'An mein Konto senden','Revoke all magic-links and codes'=>'Alle Magic-Links und Codes widerrufen','Marks every unconsumed token consumed site-wide. Already-active sessions are not signed out.'=>'Markiert jedes nicht eingelöste Token site-weit als eingelöst. Bereits aktive Sitzungen werden nicht abgemeldet.','Revoke now'=>'Jetzt widerrufen','Reset throttle counters'=>'Drosselungszähler zurücksetzen','Deletes every magicauth_throttle_* transient. Object-cache safe.'=>'Löscht jeden magicauth_throttle_*-Transient. Objekt-Cache-sicher.','Reset now'=>'Jetzt zurücksetzen','Branded login is enabled, but your WordPress salts are still weak. Magic links each carry their own random secret so they stay safe; your session cookies and the 6-character codes are better protected once you fix the salts. See the weak-salt notice for how.'=>'Die gebrandete Anmeldung ist aktiviert, aber Ihre WordPress-Salts sind noch schwach. Jeder Magic-Link trägt sein eigenes Zufallsgeheimnis und bleibt daher sicher; Ihre Sitzungs-Cookies und die 6-stelligen Codes sind besser geschützt, sobald Sie die Salts korrigieren. Wie das geht, steht im Hinweis zu schwachen Salts.','Sender address: that value had no usable characters, so it was reset to "login".'=>'Absenderadresse: Dieser Wert enthielt keine verwendbaren Zeichen und wurde auf "login" zurückgesetzt.','Logo: selected attachment is not an image.'=>'Logo: Der ausgewählte Anhang ist kein Bild.','Logo: SVG contains active content (script / event handlers / javascript:). Re-export without scripting.'=>'Logo: Das SVG enthält aktiven Inhalt (Script / Event-Handler / javascript:). Exportieren Sie es erneut ohne Skripte.','Logo: only PNG, JPG, WebP, or SVG are allowed.'=>'Logo: Nur PNG, JPG, WebP oder SVG sind erlaubt.','Logo: file content does not match a supported image format.'=>'Logo: Der Dateiinhalt entspricht keinem unterstützten Bildformat.','Link &amp; code lifetime'=>'Lebensdauer von Link &amp; Code','Both the magic link and the typeable code share one expiry. Range 1–30 minutes.'=>'Der Magic-Link und der eingebbare Code teilen sich eine Ablaufzeit. Bereich 1–30 Minuten.','minutes'=>'Minuten','Max link uses'=>'Max. Link-Nutzungen','2 absorbs URL-scanner prefetch plus the user\'s click. Set to 1 for strict single-use.'=>'2 fängt das Prefetch von URL-Scannern plus den Klick des Nutzers ab. Auf 1 setzen für strikte Einmalnutzung.','Auto (admin or home, by capability)'=>'Automatisch (Admin oder Startseite, je nach Berechtigung)','Site home'=>'Website-Startseite','Admin dashboard'=>'Admin-Dashboard','Default redirect after sign-in'=>'Standard-Weiterleitung nach der Anmeldung','Where users land when no specific destination was requested.'=>'Wo Nutzer landen, wenn kein bestimmtes Ziel angefordert wurde.','Replace WordPress login screen'=>'WordPress-Anmeldebildschirm ersetzen','Why is this flagged?'=>'Warum ist das markiert?','Heads up: weak salts'=>'Achtung: schwache Salts','You can turn this on now, but the salts in'=>'Sie können dies jetzt aktivieren, aber die Salts in','are weak — fixing them first is recommended.'=>'sind schwach — es wird empfohlen, sie zuerst zu korrigieren.','How to fix →'=>'So beheben Sie das →','Intercepts wp-login.php and serves the branded MagicAuth screen. The native form stays available at ?magicauth=off as a recovery path.'=>'Fängt wp-login.php ab und zeigt den gebrandeten MagicAuth-Bildschirm. Das native Formular bleibt unter ?magicauth=off als Wiederherstellungspfad verfügbar.','Hide language switcher'=>'Sprachumschalter ausblenden','WordPress adds a language selector to the login screen when extra languages are installed. MagicAuth places it under the card. Turn this on to hide it on the branded screen; the recovery login at ?magicauth=off keeps it.'=>'WordPress fügt dem Anmeldebildschirm einen Sprachwähler hinzu, wenn zusätzliche Sprachen installiert sind. MagicAuth platziert ihn unter der Karte. Aktivieren Sie dies, um ihn auf dem gebrandeten Bildschirm auszublenden; die Wiederherstellungs-Anmeldung unter ?magicauth=off behält ihn.','Company name'=>'Firmenname','Your short business name. No taglines, slogans, or separators.'=>'Ihr kurzer Firmenname. Keine Slogans, Claims oder Trennzeichen.','Sender email address'=>'Absender-E-Mail-Adresse','The address sign-in emails are sent from. Only the part before the @ is editable — it stays on your own domain so messages pass spam checks (SPF/DKIM/DMARC) instead of being flagged as forged. Letters, digits, and . _ - + only.'=>'Die Adresse, von der Anmelde-E-Mails gesendet werden. Nur der Teil vor dem @ ist bearbeitbar — er bleibt auf Ihrer eigenen Domain, damit Nachrichten die Spam-Prüfungen (SPF/DKIM/DMARC) bestehen, statt als gefälscht markiert zu werden. Nur Buchstaben, Ziffern und . _ - +.','PNG, JPG, or WebP. Existing SVG attachments may also be selected. Capped at 48px height on the sign-in card.'=>'PNG, JPG oder WebP. Vorhandene SVG-Anhänge können ebenfalls ausgewählt werden. Auf 48px Höhe auf der Anmeldekarte begrenzt.','Brand color'=>'Markenfarbe','Auto-derives readable button text via YIQ luminance. Current contrast:'=>'Leitet lesbaren Buttontext automatisch über YIQ-Luminanz ab. Aktueller Kontrast:','Color picker'=>'Farbwähler','Brand name'=>'Markenname','Shown bold in the credit line.'=>'Wird fett in der Credit-Zeile angezeigt.','Brand URL'=>'Marken-URL','Opens in a new tab. Must start with http:// or https://.'=>'Öffnet in einem neuen Tab. Muss mit http:// oder https:// beginnen.','Brand favicon'=>'Marken-Favicon','Square 32×32 or larger. PNG, JPG, WebP, or SVG.'=>'Quadratisch 32×32 oder größer. PNG, JPG, WebP oder SVG.','Credit label'=>'Credit-Bezeichnung','Text shown before the brand name. Leave blank for the default ("Built by").'=>'Text, der vor dem Markennamen angezeigt wird. Leer lassen für den Standard ("Erstellt von").','Built by'=>'Erstellt von','"Sign in with password" link'=>'Link "Mit Passwort anmelden"','Always-visible recovery link on every form. Only disable this if you have already disabled WordPress password authentication site-wide.'=>'Immer sichtbarer Wiederherstellungslink auf jedem Formular. Deaktivieren Sie dies nur, wenn Sie die WordPress-Passwort-Authentifizierung bereits site-weit deaktiviert haben.','Per-IP window (hours)'=>'Zeitfenster pro IP (Stunden)','Per-IP max requests'=>'Max. Anfragen pro IP','Per-IP code window (hours)'=>'Code-Zeitfenster pro IP (Stunden)','Per-IP max code attempts'=>'Max. Code-Versuche pro IP','Per-email cooldown'=>'Abklingzeit pro E-Mail','Seconds between consecutive link requests for the same email. 0 disables. Default 60. Replaced the per-email hard cap in v1.3.7. That cap was a DoS primitive any IP could weaponize against any victim email.'=>'Sekunden zwischen aufeinanderfolgenden Link-Anfragen für dieselbe E-Mail. 0 deaktiviert. Standard 60. Ersetzte das harte Limit pro E-Mail in v1.3.7. Dieses Limit war ein DoS-Primitiv, das jede IP gegen jede Opfer-E-Mail einsetzen konnte.','seconds'=>'Sekunden','Replace'=>'Ersetzen','Remove'=>'Entfernen','You are not allowed to do this.'=>'Sie dürfen dies nicht tun.','%d outstanding token revoked.'=>'%d ausstehendes Token widerrufen.' . "\0" . '%d ausstehende Token widerrufen.','%d throttle counter cleared.'=>'%d Drosselungszähler zurückgesetzt.' . "\0" . '%d Drosselungszähler zurückgesetzt.','Per-user controls'=>'Steuerung pro Benutzer','Disable magic-link sign-in for this user'=>'Magic-Link-Anmeldung für diesen Benutzer deaktivieren','Saving with this checked invalidates all outstanding sign-in links for this user immediately.'=>'Wenn Sie mit dieser Option speichern, werden alle ausstehenden Anmeldelinks für diesen Benutzer sofort ungültig.','Magic-link actions'=>'Magic-Link-Aktionen','Create magic-link'=>'Magic-Link erstellen','Send link to user'=>'Link an Benutzer senden','Reset all magic-links'=>'Alle Magic-Links zurücksetzen','Cleared on next page load. Copy now.'=>'Wird beim nächsten Laden der Seite gelöscht. Jetzt kopieren.','Could not issue link.'=>'Link konnte nicht ausgestellt werden.','Link created. Copy the URL now. It disappears on reload.'=>'Link erstellt. Kopieren Sie die URL jetzt. Sie verschwindet beim Neuladen.','wp_mail returned false. Check the server\'s mail configuration.'=>'wp_mail hat false zurückgegeben. Prüfen Sie die Mail-Konfiguration des Servers.','Link sent.'=>'Link gesendet.','%d outstanding link reset.'=>'%d ausstehender Link zurückgesetzt.' . "\0" . '%d ausstehende Links zurückgesetzt.','Missing user.'=>'Benutzer fehlt.','User not found.'=>'Benutzer nicht gefunden.','This sign-in link is for a different account.'=>'Dieser Anmeldelink gehört zu einem anderen Konto.','Sign out first if you need to switch accounts.'=>'Melden Sie sich zuerst ab, wenn Sie das Konto wechseln möchten.','Back to site'=>'Zurück zur Website','If an account exists for that email, we sent a sign-in link.'=>'Falls für diese E-Mail ein Konto existiert, haben wir einen Anmeldelink gesendet.','MagicAuth sign-in tokens'=>'MagicAuth-Anmeldetoken','Selector'=>'Selektor','Issued'=>'Ausgestellt','Expires'=>'Läuft ab','Consumed'=>'Eingelöst','not yet'=>'noch nicht','%1$s is your %2$s-code'=>'%1$s ist Ihr %2$s-Code','About your sign-in request for %s'=>'Zu Ihrer Anmeldeanfrage für %s','Sign in'=>'Anmelden','You\'re already signed in as %s.'=>'Sie sind bereits als %s angemeldet.','Sign out'=>'Abmelden','That reset link has expired or already been used. Request a new one below.'=>'Dieser Zurücksetzungslink ist abgelaufen oder wurde bereits verwendet. Fordern Sie unten einen neuen an.','That sign-in link has expired or already been used. Request a new code or link below.'=>'Dieser Anmeldelink ist abgelaufen oder wurde bereits verwendet. Fordern Sie unten einen neuen Code oder Link an.','If an account exists for that email, we sent a password reset link.'=>'Falls für diese E-Mail ein Konto existiert, haben wir einen Link zum Zurücksetzen des Passworts gesendet.','Email sent. Check your mail app.'=>'E-Mail gesendet. Prüfen Sie Ihre Mail-App.','That code is invalid or has expired. Try again, or request a new code.'=>'Dieser Code ist ungültig oder abgelaufen. Versuchen Sie es erneut oder fordern Sie einen neuen Code an.','Sign-in failed. Check your username and password, or use a magic link instead.'=>'Anmeldung fehlgeschlagen. Prüfen Sie Benutzername und Passwort oder verwenden Sie stattdessen einen Magic-Link.','Could not set a new password. Make sure both fields match and try again.'=>'Neues Passwort konnte nicht gesetzt werden. Stellen Sie sicher, dass beide Felder übereinstimmen, und versuchen Sie es erneut.','Please wait %d seconds before requesting another link for this email.'=>'Bitte warten Sie %d Sekunden, bevor Sie einen weiteren Link für diese E-Mail anfordern.','Please wait a moment before requesting another link for this email.'=>'Bitte warten Sie einen Moment, bevor Sie einen weiteren Link für diese E-Mail anfordern.','Too many sign-in requests from your network. Please try again later, or sign in with a password.'=>'Zu viele Anmeldeanfragen aus Ihrem Netzwerk. Bitte versuchen Sie es später erneut oder melden Sie sich mit einem Passwort an.','Too many code attempts from your network. Please request a new sign-in link.'=>'Zu viele Code-Versuche aus Ihrem Netzwerk. Bitte fordern Sie einen neuen Anmeldelink an.','Too many sign-in attempts. Please wait a few minutes before trying again.'=>'Zu viele Anmeldeversuche. Bitte warten Sie ein paar Minuten, bevor Sie es erneut versuchen.','Too many password-reset requests. Please wait an hour before trying again.'=>'Zu viele Anfragen zum Zurücksetzen des Passworts. Bitte warten Sie eine Stunde, bevor Sie es erneut versuchen.','Too many incorrect codes for this link. Please request a new sign-in link.'=>'Zu viele falsche Codes für diesen Link. Bitte fordern Sie einen neuen Anmeldelink an.','Dismiss'=>'Schließen','MagicAuth: response-flush helper unavailable.'=>'MagicAuth: Response-Flush-Helfer nicht verfügbar.','Your PHP runtime does not provide fastcgi_finish_request(). MagicAuth cannot defer email sending until after the response, so SMTP latency may leak whether an account exists. Switch to PHP-FPM (or LiteSpeed) for full timing parity.'=>'Ihre PHP-Laufzeit bietet kein fastcgi_finish_request(). MagicAuth kann den E-Mail-Versand nicht bis nach der Antwort verzögern, sodass die SMTP-Latenz verraten könnte, ob ein Konto existiert. Wechseln Sie zu PHP-FPM (oder LiteSpeed) für vollständige Timing-Parität.','MagicAuth: weak WordPress salts detected.'=>'MagicAuth: schwache WordPress-Salts erkannt.','Your security keys still hold placeholder or empty values, so token and session secrets are not unique to this site. Your magic links stay safe (each carries its own random secret), but fixing this is recommended — especially before turning on the branded login replacement.'=>'Ihre Sicherheitsschlüssel enthalten noch Platzhalter- oder leere Werte, daher sind Token- und Sitzungsgeheimnisse nicht eindeutig für diese Website. Ihre Magic-Links bleiben sicher (jeder trägt sein eigenes Zufallsgeheimnis), aber eine Korrektur wird empfohlen — besonders bevor Sie den gebrandeten Anmelde-Ersatz aktivieren.','Learn how to fix this'=>'Erfahren Sie, wie Sie das beheben','MagicAuth login activity'=>'MagicAuth-Anmeldeaktivität','Built by %s'=>'Erstellt von %s','A sign-in code was just requested for your account at %s.'=>'Für Ihr Konto bei %s wurde gerade ein Anmeldecode angefordert.','Magic link and code sign-in is currently turned off for your account, so no code was sent. This is a setting managed by your site administrator and is often part of routine account changes.'=>'Die Anmeldung per Magic-Link und Code ist für Ihr Konto derzeit deaktiviert, daher wurde kein Code gesendet. Dies ist eine von Ihrem Website-Administrator verwaltete Einstellung und oft Teil routinemäßiger Kontoänderungen.','You may still be able to sign in with your password through the regular sign-in screen. If you are not sure whether your account should have access, please contact your site administrator.'=>'Möglicherweise können Sie sich weiterhin mit Ihrem Passwort über den regulären Anmeldebildschirm anmelden. Wenn Sie nicht sicher sind, ob Ihr Konto Zugriff haben sollte, wenden Sie sich bitte an Ihren Website-Administrator.','If you have questions about your account access, please contact your site administrator.'=>'Wenn Sie Fragen zum Zugriff auf Ihr Konto haben, wenden Sie sich bitte an Ihren Website-Administrator.','If you did not request a sign-in code, you can ignore this message. No further action is needed.'=>'Wenn Sie keinen Anmeldecode angefordert haben, können Sie diese Nachricht ignorieren. Es ist keine weitere Aktion erforderlich.','Sign in to %s'=>'Bei %s anmelden','Use the code below or open the sign-in link. Both expire in %d minutes.'=>'Verwenden Sie den Code unten oder öffnen Sie den Anmeldelink. Beide laufen in %d Minuten ab.','Sign-in code:'=>'Anmeldecode:','Sign-in link:'=>'Anmeldelink:','If you didn\'t request this, you can safely ignore this email.'=>'Wenn Sie dies nicht angefordert haben, können Sie diese E-Mail bedenkenlos ignorieren.','(This is a test send from the MagicAuth diagnostics screen.)'=>'(Dies ist ein Testversand vom MagicAuth-Diagnosebildschirm.)','Use the code below or click the button to sign in. Both expire in %d minutes.'=>'Verwenden Sie den Code unten oder klicken Sie auf die Schaltfläche, um sich anzumelden. Beide laufen in %d Minuten ab.','Test send'=>'Testversand','Check your email'=>'Prüfen Sie Ihre E-Mail','Reset your password'=>'Setzen Sie Ihr Passwort zurück','Set a new password'=>'Legen Sie ein neues Passwort fest','Enter the verification code we sent to %s.'=>'Geben Sie den Bestätigungscode ein, den wir an %s gesendet haben.','Enter the 6-character code we just emailed you.'=>'Geben Sie den 6-stelligen Code ein, den wir Ihnen gerade per E-Mail gesendet haben.','Enter your username or email and we will send a link to set a new password.'=>'Geben Sie Ihren Benutzernamen oder Ihre E-Mail ein, und wir senden einen Link, um ein neues Passwort festzulegen.','Choose a strong password. You will be signed in once it is saved.'=>'Wählen Sie ein starkes Passwort. Sie werden angemeldet, sobald es gespeichert ist.','6-character verification code'=>'6-stelliger Bestätigungscode','Use a different email'=>'Andere E-Mail verwenden','Username or email'=>'Benutzername oder E-Mail','Password'=>'Passwort','Remember me'=>'Angemeldet bleiben','Forgot password?'=>'Passwort vergessen?','Use a magic link instead'=>'Stattdessen einen Magic-Link verwenden','Send Reset Link'=>'Zurücksetzungslink senden','Back to sign in'=>'Zurück zur Anmeldung','New password'=>'Neues Passwort','Confirm new password'=>'Neues Passwort bestätigen','Save and sign in'=>'Speichern und anmelden','Email address'=>'E-Mail-Adresse','Send Link'=>'Link senden','Sign in with password'=>'Mit Passwort anmelden','Change language. Current:'=>'Sprache ändern. Aktuell:']];